--- i18n module for PSDToolKit v2.0.0alpha10 by oov
local M = {}

-- Cached preferred language list
local preferred_langs = nil

--- Get preferred languages from script module (cached)
-- @return table: Array of language codes (e.g., {"ja_JP", "en_US"})
local function get_preferred_languages()
	if preferred_langs then
		return preferred_langs
	end
	local ptk = obj.module("PSDToolKit")
	if ptk and ptk.get_preferred_languages then
		preferred_langs = ptk.get_preferred_languages()
		if not preferred_langs or #preferred_langs == 0 then
			preferred_langs = { "en_US" }
		end
	else
		preferred_langs = { "en_US" }
	end
	return preferred_langs
end

--- Extract primary language from language code
-- @param code string: Language code (e.g., "ja_JP")
-- @return string: Primary language (e.g., "ja")
local function get_primary_lang(code)
	return string.match(code, "^([^_]+)")
end

--- Select the best matching text from a table based on system language.
-- @param tbl table: Keys are language codes (ja_JP, en_US, etc.), values are text
-- @param override string|nil: Optional language code to override system preference
-- @return string|nil: Selected text
function M.i18n(tbl, override)
	if type(tbl) ~= "table" then
		error("i18n requires a table argument")
	end

	local langs = get_preferred_languages()

	-- If override is provided, prepend it to the language list
	if override and type(override) == "string" then
		local override_langs = { override }
		for _, v in ipairs(langs) do
			table.insert(override_langs, v)
		end
		langs = override_langs
	end

	-- Exact match
	for _, lang in ipairs(langs) do
		if tbl[lang] then
			return tbl[lang]
		end
	end

	-- Primary language match
	for _, lang in ipairs(langs) do
		local primary = get_primary_lang(lang)
		for key, value in pairs(tbl) do
			if get_primary_lang(key) == primary then
				return value
			end
		end
	end

	-- Fallback: en_US, then first entry
	if tbl.en_US then
		return tbl.en_US
	end

	for _, value in pairs(tbl) do
		return value
	end

	return nil
end

return M

end

package.preload['PSDToolKit.util'] = function(...)
local M = {}

--- Gets the byte offset for the nth UTF-8 character in a string.
-- @param s string: The input UTF-8 string.
-- @param pos number: The character position (1-based, positive only).
-- @return number: The byte offset of the character, or #s + 1 if out of bounds.
local function utf8_offset(s, pos)
	if pos == 1 then
		return 1
	end
	local char_count = 0
	local i = 1
	while i <= #s and char_count < pos - 1 do
		local c = s:byte(i)
		if c < 128 then
			i = i + 1
		elseif c < 224 then
			i = i + 2
		elseif c < 240 then
			i = i + 3
		else
			i = i + 4
		end
		char_count = char_count + 1
	end
	if char_count == pos - 1 then
		return i
	else
		return #s + 1
	end
end

--- Gets a substring of a UTF-8 encoded string.
-- @param s string: The input UTF-8 string.
-- @param i number: The starting character position (1-based, positive only).
-- @param j number: The ending character position (1-based, positive only, -1 for end of string, defaults to -1).
-- @return string: The extracted substring, or nil if the input is not valid UTF-8.
local function utf8_sub(s, i, j)
	if not s then
		return nil
	end
	i = i or 1
	j = j or -1
	if i < 1 then
		return ""
	end
	if j ~= -1 and (j < 1 or i > j) then
		return ""
	end
	local start_byte = utf8_offset(s, i)
	if not start_byte then
		return nil
	end
	local end_byte = j == -1 and #s + 1 or utf8_offset(s, j + 1)
	if not end_byte then
		return nil
	end
	return s:sub(start_byte, end_byte - 1)
end

--- Gets a truncated version of s.
-- @param s string: The input string.
-- @param length number: The maximum length of the string.
-- @return string: The truncated string with "..." appended if it exceeds the specified length.
function M.truncate_string(s, length)
	local d = utf8_sub(s, 1, length)
	if #s > #d then
		return d .. "..."
	end
	return s
end

return M

end

