		end
		obj.mes(text)
		obj.ox = obj.ox + vs.x
		obj.oy = obj.oy + vs.y
		obj.oz = obj.oz + vs.z
		return vs
	end)
	if not ok then
		mes(tostring(err))
	end
end

M.init_psd = CurrentPSD.init
M.draw_psd = CurrentPSD.draw
M.add_lipsync = CurrentPSD.add_lipsync
M.add_lipsync_lab = CurrentPSD.add_lipsync_lab
